"$sourceDir = "C:\Users\smile\agency-agents"
$targetDir = "C:\Users\smile\.gemini\antigravity\skills"

$agentDirs = @("academic", "design", "engineering", "finance", "game-development", "marketing", "paid-media", "product", "project-management", "sales", "spatial-computing", "specialized", "strategy", "support", "testing")

$today = (Get-Date).ToString("yyyy-MM-dd")
$count = 0

foreach ($dir in $agentDirs) {
    $fullDirPath = Join-Path $sourceDir $dir
    if (Test-Path $fullDirPath) {
        $files = Get-ChildItem -Path $fullDirPath -Filter "*.md"
        foreach ($file in $files) {
            $content = Get-Content $file.FullName -Raw

            # Check for frontmatter
            if ($content -match "(?s)^---\r?\n(.*?)\r?\n---\r?\n(.*)$") {
                $frontmatter = $matches[1]
                $body = $matches[2]

                $name = ""
                $desc = ""
                if ($frontmatter -match "(?m)^name:\s*(.+)$") {
                    $name = $matches[1].Trim()
                }
                if ($frontmatter -match "(?m)^description:\s*(.+)$") {
                    $desc = $matches[1].Trim()
                }

                if ($name) {
                    $slugName = $name.ToLower() -replace '[^a-z0-9]', '-' -replace '-+', '-' -replace '^-|-$', ''
                    $slug = "agency-$slugName"

                    $outDir = Join-Path $targetDir $slug
                    if (-not (Test-Path $outDir)) {
                        New-Item -ItemType Directory -Force -Path $outDir | Out-Null
                    }

                    $outFile = Join-Path $outDir "SKILL.md"
                    $newContent = "---`nname: $slug`ndescription: $desc`nrisk: low`nsource: community`ndate_added: '$today'`n---`n$body"
                    Set-Content -Path $outFile -Value $newContent -Encoding UTF8

